Redeclare the abstract variables in your class without the AbstractVar wrapper.
See here:
Copy
import diffrax as dx
import jax.numpy as jnp
import equinox as eqx

class MySimpleWrapper(dx.AbstractSolver):
    solver: dx.AbstractSolver = eqx.field(static=True) # Use static=True for fixed solver

    def __init__(self, solver: dx.AbstractSolver):
        self.solver = solver

    @property
    def interpolation_cls(self):
        return self.solver.interpolation_cls

    # Delegate all required methods directly to the wrapped solver
    def func(self, terms, t, y, args):
        return self.solver.func(terms, t, y, args)

    def init(self, terms, t0, t1, y0, args, saveat, fn):
        return self.solver.init(terms, t0, t1, y0, args, saveat, fn)

    def step(self, terms, t0, t1, y0, args, solver_state, made_jump):
        return self.solver.step(terms, t0, t1, y0, args, solver_state, made_jump)

# This now instantiates and can be used
obj = MySimpleWrapper(dx.Tsit5())
print(f"Success! Created {type(obj).__name__}")

# You can even use it in a solve
def f(t, y, args):
    return -y

term = dx.ODETerm(f)
sol_custom = dx.diffeqsolve(term, obj, t0=0, t1=1, dt0=0.1, y0=1.0)
print(f"MySimpleWrapper solution (first value): {sol_custom.ys[0]}")
